    for i in range(tl-2, 0, -1):
        line = lines[i-1]
        if line.strip().startswith('def '):
            # Check for decorators before this
            decorators = []
            for j in range(i-2, 0, -1):
                l = lines[j-1]
                if l.strip().startswith('@'):
                    decorators.append(l.strip())
                else:
                    break
            decorators.reverse()
            dec_str = ', '.join(decorators) if decorators else 'none'
